import { reverseConnectorService } from "./ReverseConnectorService.js";

export async function fetchReverseConnectorMasterList() {
    let response = await reverseConnectorService.fetchReverseConnectorMasterList();
    return response;
}

export async function fetchReverseConnectorConfig() {
    let response = await reverseConnectorService.fetchReverseConnectorConfig();
    return response;
}

export async function saveReverseConnectorConfig(config) {
    let response = await reverseConnectorService.saveReverseConnectorConfig(config);
    return response;
}
